Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();

  // Firebase must be initialised before any Firebase SDK call.
  // This also restores the previously saved Auth token so that
  // authStateChanges() can emit the persisted User on first listen.
  await Firebase.initializeApp(
    options: DefaultFirebaseOptions.currentPlatform,
  );

  // Keep status bar transparent with dark icons (matches white AppBar).
  SystemChrome.setSystemUIOverlayStyle(
    const SystemUiOverlayStyle(
      statusBarColor:                   Colors.transparent,
      statusBarIconBrightness:          Brightness.dark,
      systemNavigationBarColor:         Colors.white,
      systemNavigationBarIconBrightness: Brightness.dark,
    ),
  );

  // Lock to portrait — remove if landscape is required.
  await SystemChrome.setPreferredOrientations([
    DeviceOrientation.portraitUp,
    DeviceOrientation.portraitDown,
  ]);

  runApp(const WaitlessApp());
}

// ─────────────────────────────────────────────────────────────────
// WaitlessApp — MaterialApp root
// ─────────────────────────────────────────────────────────────────
class WaitlessApp extends StatelessWidget {
  const WaitlessApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Waitless',
      debugShowCheckedModeBanner: false,
      theme: AppTheme.lightTheme,

      // _AuthGate is the REAL home. It never shows RoleSelectionScreen
      // to a user who is already logged in — it routes them directly
      // to their role-appropriate home screen.
      home: const SplashScreen(),
    );
  }
}

// ─────────────────────────────────────────────────────────────────
// _AuthGate — StreamBuilder wrapper for auth-state-driven routing
//
// BLACK BOOK — Why StreamBuilder instead of FutureBuilder here?
//   FutureBuilder fires once. StreamBuilder fires on every emission.
//   authStateChanges() emits again whenever the auth state changes
//   (login → logout → delete), so the UI reacts automatically
//   without any Navigator calls from service or dialog code.
// ─────────────────────────────────────────────────────────────────
class _AuthGate extends StatelessWidget {
  const _AuthGate();

  @override
  Widget build(BuildContext context) {
    return StreamBuilder<User?>(
      // REQUIREMENT 1: listen to Firebase Auth session stream.
      // Firebase restores the saved token on app restart so this
      // stream immediately emits the persisted User without a login.
      stream: FirebaseAuth.instance.authStateChanges(),

      builder: (context, authSnapshot) {

        // ── State 1: Firebase is still initialising ──────────────
        // ConnectionState.waiting on the very first frame before
        // Firebase has replied. Show a branded splash to avoid flash.
        if (authSnapshot.connectionState == ConnectionState.waiting) {
          return const Scaffold(backgroundColor: AppColors.background);
        }

        // ── State 2: Nobody signed in ─────────────────────────────
        // authSnapshot.data is null → no active session.
        // Show role selection so the user can log in or register.
        if (!authSnapshot.hasData || authSnapshot.data == null) {
          return const RoleSelectionScreen();
        }

        // ── State 3: User is signed in ────────────────────────────
        // We have a User with a UID. Now we need to know whether
        // they are a patient or a doctor to route correctly.
        // This is a second async step so we use another FutureBuilder.
        final String uid = authSnapshot.data!.uid;
        return _RoleRouter(uid: authSnapshot.data!.uid);
      },
    );
  }
}

class _RoleRouter extends StatefulWidget {
  const _RoleRouter({required this.uid});
  final String uid;

  @override
  State<_RoleRouter> createState() => _RoleRouterState();
}

class _RoleRouterState extends State<_RoleRouter> {
  late final Future<String?> _roleFuture;

  @override
  void initState() {
    super.initState();
    _roleFuture = _getRole();
  }

  Future<String?> _getRole() async {
    final db = FirebaseFirestore.instance;
    final patientDoc = await db.collection('patients').doc(widget.uid).get();
    if (patientDoc.exists) return 'patient';
    final doctorDoc = await db.collection('doctors').doc(widget.uid).get();
    if (doctorDoc.exists) return 'doctor';
    return null;
  }

  @override
  Widget build(BuildContext context) {
    return FutureBuilder<String?>(
      future: _roleFuture,
      builder: (context, snap) {
        if (snap.connectionState == ConnectionState.waiting) {
          return const _SplashScreen();
        }
        final role = snap.data;
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (!context.mounted) return;
          final dest = switch (role) {
            'doctor'  => const DocHomeScreen(),
            'patient' => const PatientHomeScreen(),
            _         => const RoleSelectionScreen(),
          };
          Navigator.pushAndRemoveUntil(
            context,
            MaterialPageRoute(builder: (_) => dest),
                (_) => false,
          );
        });
        return const _SplashScreen();
      },
    );
  }
}

