// ─────────────────────────────────────────────────────────────────
// _SplashScreen — shown while Firebase / Firestore resolves
//
// Branded loading screen so the user sees the app name rather than
// a white flash during the async auth + role lookup.
// ─────────────────────────────────────────────────────────────────
class _SplashScreen extends StatelessWidget {
  const _SplashScreen();

  @override
  Widget build(BuildContext context) {
    return const Scaffold(
      backgroundColor: AppColors.background,
      body: Center(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(
              'Waitless',
              style: TextStyle(
                fontFamily:  'Nunito',
                fontSize:    36,
                fontWeight:  FontWeight.w800,
                color:       AppColors.primary,
                letterSpacing: -1.0,
              ),
            ),
            SizedBox(height: 24),
            CircularProgressIndicator(
              color:       AppColors.primary,
              strokeWidth: 2.5,
            ),
          ],
        ),
      ),
    );
  }
}
